import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

const Home = () => {
  const navigate = useNavigate();

  useEffect(() => {
    const lightElement = document.getElementById("light");
    if (lightElement) {
      setInterval(() => {
        lightElement.setAttribute("fill", lightElement.getAttribute("fill") === "#e7e5d5" ? "#ffe966" : "#e7e5d5");
      }, 2000);
    }
  }, []);

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">
      <svg
        className="photoautomat-svg"
        width="300"
        height="400"
        viewBox="0 0 300 400"
        xmlns="http://www.w3.org/2000/svg"
      >
        <image href="/photoautomat.svg" width="300" height="400" />
        <circle id="light" cx="250" cy="250" r="20" fill="#e7e5d5" />
      </svg>

      <button onClick={() => navigate("/welcome")} className="start-button">
        START
      </button>
    </div>
  );
};

export default Home;
